from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

# Database connection settings
DB_HOST = 'localhost'
DB_NAME = 'database_name'
DB_USER = 'database_user'
DB_PASSWORD = 'database_password'

def get_db_connection():
    return psycopg2.connect(
        host=DB_HOST,
        database=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
        cursor_factory=RealDictCursor
    )

@app.route('/query', methods=['POST'])
def query_database():
    data = request.json

    table_name = data.get('table')
    columns = data.get('columns')
    filters = data.get('filters')

    if not table_name or not columns or not filters:
        return jsonify({'error': 'Missing required parameters'}), 400

    # Prevent SQL injection by whitelisting allowed column names and filter conditions
    allowed_columns = ['column1', 'column2']  # Replace with actual column names
    allowed_filters = ['filter1', 'filter2']  # Replace with actual filter conditions

    query = """
        SELECT {}
        FROM {}
        WHERE {}
    """.format(
        ', '.join([col for col in columns if col in allowed_columns]),
        table_name,
        ' AND '.join([
            '{} = %s'.format(filter_) 
            for filter_ in filters['values'] 
            if filter_.get('column') in allowed_filters
        ])
    )

    conn = get_db_connection()
    cur = conn.cursor()

    try:
        cur.execute(query, [filter_.get('value') for filter_ in filters['values']])
        result = cur.fetchall()
        return jsonify(result)
    except psycopg2.Error as e:
        return jsonify({'error': str(e)}), 500
    finally:
        conn.close()

if __name__ == '__main__':
    app.run(debug=True)